// 1. Accedemos a la data siguiendo tu estructura: $json.output
const data = $json.output; 

// Verificamos que existan las evaluaciones
const evaluaciones = data.evaluacion || [];
const mensajeResumen = data.mensaje_para_usuario || "Examen procesado.";

let textoFinal = "📊 *RESULTADOS DE TU EVALUACIÓN* \n";
textoFinal += "━━━━━━━━━━━━━━━━━━━━━\n\n";

// 2. Variables para el contador de puntos
let correctas = 0;

// 3. Iteramos las preguntas
evaluaciones.forEach((item) => {
  const esCorrecta = item.estado === "APROBADO";
  if (esCorrecta) correctas++;

  const icono = esCorrecta ? "✅" : "❌";

  textoFinal += `${icono} *Pregunta ${item.nro_pregunta}:* ${item.pregunta}\n`;
  textoFinal += `*Estado:* _${item.estado}_\n`;

  if (!esCorrecta) {
    textoFinal += `💡 *Respuesta Correcta:* ${item.respuesta_correcta}\n`;
  }

  textoFinal += `📝 *Feedback:* ${item.feedback}\n`;
  textoFinal += "─────────────────────\n";
});

// 4. Puntaje final visual
const total = evaluaciones.length;
const porcentaje = (correctas / total) * 100;
let medalla = porcentaje >= 70 ? "🏆" : "📚";

textoFinal += `\n${medalla} *Puntaje Final:* ${correctas}/${total}\n`;
textoFinal += `📌 *Resumen:* ${mensajeResumen}\n\n`;
textoFinal += "¡Seguí metiéndole garra al estudio! 💪";

return { texto_whatsapp: textoFinal };

