        .espacio-desarrollo { height: 120px; border: 1px dashed #BDC3C7; border-radius: 5px; margin-top: 15px; background-color: #fff; }
        .footer { margin-top: 50px; font-size: 12px; text-align: center; color: #95A5A6; border-top: 1px solid #ECF0F1; padding-top: 20px; }
    </style>
</head>
<body>
    <div class="header-container">
        <h1>Examen de Evaluación</h1>
        <div class="subtitle">Prueba generada por Inteligencia Artificial</div>
    </div>

    <div class="student-info">
        <div><span>Nombre:</span> ____________________________________</div>
        <div><span>Fecha:</span> ________________</div>
    </div>
`;

preguntas.forEach((p, i) => {
    html += `
    <div class="pregunta">
        <span class="tipo">${p.tipo.replace('_', ' ')}</span>
        <div class="texto-pregunta">${i + 1}. ${p.pregunta}</div>
    `;

    if (p.opciones && p.opciones.length > 0) {
        html += `<ul class="opciones">`;
        p.opciones.forEach(opt => {
            html += `<li class="opcion"><span class="caja"></span> ${opt}</li>`;
        });
        html += `</ul>`;
    } else {
        html += `<div class="espacio-desarrollo"></div>`;
    }
    html += `</div>`;
});

html += `
    <div class="footer">Documento autogenerado. Por favor, responda con claridad en los espacios indicados.</div>
</body>
</html>`;

return { html_content: html };

// 1. Obtenemos el string de preguntas (que viene como texto con escapes)
let preguntasRaw = $input.first().json.preguntas

// 2. Lo convertimos en un objeto real de JS
let listaPreguntas = JSON.parse(preguntasRaw);

let textoFinal = "📝 *NUEVO EXAMEN GENERADO* \n\n";

listaPreguntas.forEach((p, index) => {
  textoFinal += `*${index + 1}. ${p.pregunta}*\n`;

  // Si tiene opciones (Multiple Choice o Verdadero/Falso), las listamos
  if (p.opciones && p.opciones.length > 0) {
    p.opciones.forEach((opcion, i) => {
      textoFinal += `   ${String.fromCharCode(97 + i)}) ${opcion}\n`; // a), b), c)...
    });
  }

  textoFinal += "\n"; // Espacio entre preguntas
});

return { texto_formateado: textoFinal };;

